ee:variables.ee:set-variable:
%dw 2.0
output application/java

var msgCorrelationId = if(attributes == null) null 
	else (
		if (attributes..'x-correlation-id'[0] != null) attributes..'x-correlation-id'[0]
		else
			attributes..'x_correlation_id'[0]
	)

var newTransaction = 
	(
		msgCorrelationId == null 
		or
		vars.com_setContext_in.isRootTransaction == "true"
	) as Boolean
---
{
	correlationId: if (newTransaction)
		(java!java::util::UUID::randomUUID() as String) replace /-/ with ''
	else if (vars.com_setContext_in.overwriteCorrelationId != null)
		vars.com_setContext_in.overwriteCorrelationId
	else msgCorrelationId,

	serviceId: (java!java::util::UUID::randomUUID() as String) replace /-/ with '',

	(isRootTransaction: 'true') if(newTransaction),
	(
		transactionName: if(vars.com_setContext_in.overwriteTransactionName?)
			vars.com_setContext_in.overwriteTransactionName
		else
			'tx.' ++ (vars.com_setContext_in.serviceName as String)
	) if(newTransaction)
}

%dw 2.0 output application/json skipNullOn="everywhere" --- [ { "tracking": vars.com_tracking, "serviceContext": vars.com_serviceContext,
serviceStatus: vars.com_serviceStatus,
log: {
logTimestamp: now() as String { format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ" }, logRole: "INFO", logStep:"START", logText:"Service started.",
}, (businessKeys: vars.com_logStart_in.businessKeys) if(vars.com_logStart_in.businessKeys?), messageProperties: vars.com_messageProperties,
(messagePayload: vars.com_messagePayload) if(vars.com_LogPayloadLogic == 'ALWAYS'),
} ]

%dw 2.0 output application/json skipNullOn="everywhere" --- [ {
"tracking": vars.com_tracking, "serviceContext": vars.com_serviceContext,
serviceStatus: vars.com_serviceStatus, log: { logTimestamp: now() as String { format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ" }, logRole: "ERROR", logStep:"ERROR", logText: vars.com_exception.errorDescription, error: vars.com_exception }, (messagePayload: vars.com_messagePayload) if(vars.com_LogPayloadLogic == 'ONERROR') } ]

%dw 2.0 output application/json skipNullOn="everywhere" --- [ {
"tracking": vars.com_tracking, "serviceContext": vars.com_serviceContext,
serviceStatus: vars.com_serviceStatus, log: { logTimestamp: now() as String { format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ" }, logRole: "WARNING", logStep:"AUDIT", logText: vars.com_exception.errorDescription, error: vars.com_exception }, (messagePayload: vars.com_messagePayload) if(vars.com_LogPayloadLogic == 'ONERROR') } ]
